const results = $json["data"]["result"];

const grouped = {};

for (const item of results) {
  const pod = item.metric.pod;
  const namespace = item.metric.namespace;
  const cpu = parseFloat(item.value[1]);

  // Extract app name (prefix before first hyphen)
  const app = pod.split('-')[0];

  if (!grouped[app]) grouped[app] = [];

  grouped[app].push({
    pod,
    namespace,
    cpu,
    app
  });
}

// Convert grouped object into items for n8n SplitOut
const output = [];

for (const app in grouped) {
  output.push({
    json: {
      app,
      pods: grouped[app]
    }
  });
}

return output;

